class Solution {
public:
    vector<char> solve(vector<vector<int>>& maze) {
        int m = maze.size();
        int n = maze[0].size();
        vector<vector<bool>> visited(m, vector<bool>(n, false));
        vector<char> path;
        vector<int> dx = {1, 0, -1, 0};
        vector<int> dy = {0, 1, 0, -1};
        backtrack(maze, visited, path, 0, 0, dx, dy);
        return path;
    }

    void backtrack(vector<vector<int>>& maze, vector<vector<bool>>& visited, vector<char>& path, int x, int y, vector<int>& dx, vector<int>& dy) {
        if (x == maze.size() - 1 && y == maze[0].size() - 1) {
            return;
        }
        if (x < 0 || x >= maze.size() || y < 0 || y >= maze[0].size() || visited[x][y] || maze[x][y] == 1) {
            return;
        }
        visited[x][y] = true;
        path.push_back('U');
        backtrack(maze, visited, path, x + dx[0], y + dy[0], dx, dy);
        path.pop_back();
        path.push_back('R');
        backtrack(maze, visited, path, x + dx[1], y + dy[1], dx, dy);
        path.pop_back();
        path.push_back('D');
        backtrack(maze, visited, path, x + dx[2], y + dy[2], dx, dy);
        path.pop_back();
        path.push_back('L');
        backtrack(maze, visited, path, x + dx[3], y + dy[3], dx, dy);
        path.pop_back();
    }
};

