var solve = function(maze) {
    var m = maze.length;
    var n = maze[0].length;
    var visited = new Array(m).fill(false).map(function() {
        return new Array(n).fill(false);
    });
    var path = [];
    var dx = [1, 0, -1, 0];
    var dy = [0, 1, 0, -1];
    function backtrack(x, y) {
        if (x == m-1 && y == n-1) {
            return path;
        }
        if (x < 0 || x >= m || y < 0 || y >= n || visited[x][y] || maze[x][y] == 1) {
            return null;
        }
        visited[x][y] = true;
        path.push('U');
        var result = backtrack(x + dx[0], y + dy[0]);
        if (result != null) {
            return result;
        }
        path.pop();
        path.push('R');
        result = backtrack(x + dx[1], y + dy[1]);
        if (result != null) {
            return result;
        }
        path.pop();
        path.push('D');
        result = backtrack(x + dx[2], y + dy[2]);
        if (result != null) {
            return result;
        }
        path.pop();
        path.push('L');
        result = backtrack(x + dx[3], y + dy[3]);
        if (result != null) {
            return result;
        }
        path.pop();
        return null;
    }
    return backtrack(0, 0);
}

